                        </div>
                        <div className="p-3 bg-[#1e1e1e] border-t border-[#333] flex gap-2">
                          <div className="px-2 py-0.5 bg-blue-900/40 text-blue-400 text-[10px] rounded border border-blue-800/50">Auto-Generated</div>
                          <div className="px-2 py-0.5 bg-green-900/40 text-green-400 text-[10px] rounded border border-green-800/50">Optimized</div>
                        </div>
                      </div>
                    )}
