                </div>
              ) : (
                <div className="flex-1 flex flex-col p-6 overflow-hidden">
                  <div className="mb-6 flex items-center justify-between shrink-0">
                    <div>
                      <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-purple-600" /> Block Density Heatmap
                      </h3>
                      <p className="text-xs text-gray-500 mt-1">Cross-sectional analysis of Entity vs Period data presence.</p>
                    </div>
                    <div className="flex gap-4 p-2 bg-white rounded-lg border border-gray-200 text-[10px] font-bold">
                       <div className="flex items-center gap-1.5"><span className="w-3 h-3 bg-gray-100 rounded"></span> NO DATA</div>
                       <div className="flex items-center gap-1.5"><span className="w-3 h-3 bg-purple-200 rounded"></span> LOW</div>
                       <div className="flex items-center gap-1.5"><span className="w-3 h-3 bg-purple-600 rounded"></span> HIGH</div>
                    </div>
                  </div>

                  <div className="flex-1 bg-white border border-gray-200 rounded-xl shadow-sm p-6 overflow-auto custom-scrollbar">
                    <div className="min-w-max">
                      {/* Header Row */}
                      <div className="flex mb-4">
                        <div className="w-24 shrink-0"></div>
                        {heatmapData?.[0]?.data.map((d: any) => (
                          <div key={d.period} className="w-16 text-center text-[10px] font-black text-gray-400 uppercase tracking-tight">{d.period}</div>
                        ))}
                      </div>

                      {heatmapData?.map((row) => (
                        <div key={row.entity} className="flex mb-2 group">
                          <div className="w-24 shrink-0 text-xs font-bold text-gray-500 flex items-center group-hover:text-purple-600 transition-colors">{row.entity}</div>
                          <div className="flex gap-2">
                            {row.data.map((cell: any) => (
                              <div 
                                key={cell.period}
                                onClick={() => {
                                  setFilters({...filters, entity: row.entity, period: cell.period});
                                  setSearchMode('query');
                                  handleRun();
                                }}
                                className={`w-16 h-10 rounded-md cursor-pointer transition-all border border-white hover:ring-2 hover:ring-purple-400 hover:scale-105 flex items-center justify-center
                                ${cell.val === 0 ? 'bg-gray-100' : cell.val < 100 ? 'bg-purple-200' : 'bg-purple-600'}`}
                                title={`${row.entity} / ${cell.period}: ${cell.val} Records`}
                              >
                                {cell.val > 0 && <span className={`text-[10px] font-bold ${cell.val > 100 ? 'text-white' : 'text-purple-700'}`}>{cell.val}</span>}
                              </div>
                            ))}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="mt-4 p-4 bg-purple-50 rounded-xl border border-purple-100 flex items-center gap-3">
                    <Info className="w-4 h-4 text-purple-400" />
                    <p className="text-[10px] text-purple-700 leading-tight">
                      <strong>PRO TIP:</strong> Click any heatmap cell to instantly jump to the detailed Query view for that specific Entity and Period slice.
                    </p>
                  </div>
                </div>
              )}

            </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default DataQuery;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Play, Search, Table, Radar, Code2, Clock, 
  ChevronDown, Database, Download, Filter, 
  Terminal, Sparkles, Activity, Layers, ArrowRight,
  Info, Globe, History, X, Save, Bookmark, Trash2, ChevronLeft, ChevronRight,
  MoreHorizontal, ListFilter, ExternalLink
} from 'lucide-react';

type SearchMode = 'query' | 'discovery';
type QueryResultTab = 'table' | 'sql';

interface HistoryItem {
  id: string;
  name: string;
  timestamp: string;
  mode: SearchMode;
  pov: { year: string; scenario: string; version: string };
  filters: Record<string, string>;
}

interface MenuState {
  entity: string;
  period: string;
  x: number;
  y: number;
}

const DataQuery: React.FC = () => {
  const [searchMode, setSearchMode] = useState<SearchMode>('query');
  const [queryTab, setQueryTab] = useState<QueryResultTab>('table');
  const [isProcessing, setIsProcessing] = useState(false);
  const [hasData, setHasData] = useState(false);
  const [showHistory, setShowHistory] = useState(true);
  const [activeMenu, setActiveMenu] = useState<MenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // POV State (Global Context)
  const [pov, setPov] = useState({
    year: '2024',
    scenario: 'Actual',
    version: 'Working'
  });

  // Local Filters
  const [filters, setFilters] = useState<Record<string, string>>({
    entity: 'China_HQ',
    period: '',
    account: ''
  });

  // Query History State
  const [history, setHistory] = useState<HistoryItem[]>([
    {
      id: 'h1',
      name: 'Q1 Revenue Audit',
      timestamp: '10 mins ago',
      mode: 'query',
      pov: { year: '2024', scenario: 'Actual', version: 'Final' },
      filters: { entity: 'China_HQ', period: 'Jan', account: '6001' }
    },
    {
      id: 'h2',
      name: 'Sparse Data Scan',
      timestamp: '1 hour ago',
      mode: 'discovery',
      pov: { year: '2024', scenario: 'Budget', version: 'Working' },
      filters: { entity: '', period: '', account: '' }
    }
  ]);

  // Mock Heatmap State
  const [heatmapData, setHeatmapData] = useState<any[] | null>(null);

  // Close menu on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setActiveMenu(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleRun = (overrideFilters?: Record<string, string>) => {
    setIsProcessing(true);
    const currentFilters = overrideFilters || filters;

    // Simulate API delay
    setTimeout(() => {
      if (searchMode === 'discovery' && !overrideFilters) {
        const entities = ['China_HQ', 'US_Branch', 'EU_Sales', 'Japan_Ops', 'India_RD'];
        const periods = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
        setHeatmapData(entities.map(e => ({
          entity: e,
          data: periods.map(p => ({ period: p, val: Math.random() > 0.4 ? Math.floor(Math.random() * 200) : 0 }))
        })));
      }

      // Add to history
      const newHistory: HistoryItem = {
        id: Date.now().toString(),
        name: searchMode === 'query' ? `Query_${currentFilters.entity || 'All'}` : `Scan_${pov.year}`,
        timestamp: 'Just now',
        mode: searchMode,
        pov: { ...pov },
        filters: { ...currentFilters }
      };
      setHistory(prev => [newHistory, ...prev].slice(0, 10)); // Keep last 10

      setHasData(true);
      setIsProcessing(false);
      setActiveMenu(null);
    }, 800);
  };

  const loadHistory = (item: HistoryItem) => {
    setSearchMode(item.mode);
    setPov(item.pov);
    setFilters(item.filters);
  };

  const navigateToDetail = (entity: string, period: string) => {
    const newFilters = { ...filters, entity, period };
    setFilters(newFilters);
    setSearchMode('query');
    setQueryTab('table');
    handleRun(newFilters); // Directly pass new filters to ensure handleRun uses latest data
  };

  const getGeneratedSql = () => {
    return `SELECT 
    account_code, period, SUM(amount) as val 
FROM fact_sales_monthly_v1
WHERE scenario = '${pov.scenario}'
  AND year = ${pov.year}
  AND version = '${pov.version}'
  ${filters.entity ? `AND entity = '${filters.entity}'` : ''}
  ${filters.account ? `AND account_code LIKE '%${filters.account}%'` : ''}
GROUP BY account_code, period
ORDER BY period ASC;`;
  };

  const handleCellClick = (e: React.MouseEvent, entity: string, period: string) => {
    e.preventDefault();
    const rect = e.currentTarget.getBoundingClientRect();
    setActiveMenu({
      entity,
      period,
      x: rect.left,
      y: rect.bottom + window.scrollY
    });
  };

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] relative">

      {/* Heatmap Context Menu */}
      {activeMenu && (
        <div 
          ref={menuRef}
          className="fixed z-[100] bg-white border border-gray-200 rounded-lg shadow-xl py-1 min-w-[160px] animate-in fade-in zoom-in duration-100"
          style={{ left: activeMenu.x, top: activeMenu.y + 4 }}
        >
          <div className="px-3 py-2 border-b border-gray-100 flex flex-col">
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">Context Slice</span>
            <span className="text-xs font-bold text-gray-700">{activeMenu.entity} · {activeMenu.period}</span>
          </div>
          <button 
            onClick={() => navigateToDetail(activeMenu.entity, activeMenu.period)}
            className="w-full flex items-center gap-2 px-3 py-2.5 text-xs text-blue-600 font-bold hover:bg-blue-50 transition-colors"
          >
            <ExternalLink className="w-3.5 h-3.5" />
            查看数据明细
          </button>
          <button className="w-full flex items-center gap-2 px-3 py-2 text-xs text-gray-500 hover:bg-gray-50 transition-colors">
            <Bookmark className="w-3.5 h-3.5" />
            保存为收藏
          </button>
        </div>
      )}

      {/* 1. Global POV Bar */}
      <div className="h-14 bg-white border-b border-gray-200 px-6 flex items-center gap-6 shrink-0 z-30 shadow-sm">
        <div className="flex items-center gap-2 border-r border-gray-200 pr-6">
          <button 
            onClick={() => setShowHistory(!showHistory)}
            className={`p-1.5 rounded transition-colors ${showHistory ? 'bg-blue-50 text-blue-600' : 'text-gray-400 hover:bg-gray-100'}`}
            title="Toggle History"
          >
            <History className="w-4 h-4" />
          </button>
          <Globe className="w-4 h-4 text-blue-600 ml-2" />
          <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Global POV</span>
        </div>

        <div className="flex gap-4">
          {Object.entries(pov).map(([key, val]) => (
            <div key={key} className="flex items-center gap-2 group cursor-pointer">
              <span className="text-[10px] font-bold text-gray-400 uppercase">{key}:</span>
              <div className="flex items-center gap-1 bg-blue-50 px-2 py-1 rounded text-xs font-bold text-blue-700 border border-blue-100 group-hover:bg-blue-100 transition-colors">
                {val} <ChevronDown className="w-3 h-3" />
              </div>
            </div>
          ))}
        </div>

        <div className="ml-auto flex items-center gap-3">
          <div className="flex bg-gray-100 p-1 rounded-lg border border-gray-200">
            <button 
              onClick={() => { setSearchMode('query'); setHasData(false); }}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${searchMode === 'query' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <Search className="w-3.5 h-3.5" /> Query
            </button>
            <button 
              onClick={() => { setSearchMode('discovery'); setHasData(false); }}
              className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${searchMode === 'discovery' ? 'bg-white text-purple-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              <Radar className="w-3.5 h-3.5" /> Discovery
            </button>
          </div>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">

        {/* 2. History Sidebar */}
        {showHistory && (
          <div className="w-[260px] bg-gray-50 border-r border-gray-200 flex flex-col shrink-0 animate-in slide-in-from-left duration-300">
            <div className="p-4 border-b border-gray-200 bg-white flex justify-between items-center">
              <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                 <Bookmark className="w-3.5 h-3.5" /> Query History
              </h3>
              <span className="text-[10px] bg-gray-100 text-gray-400 px-1.5 py-0.5 rounded font-mono">LATEST 10</span>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
              {history.map(item => (
                <div 
                  key={item.id}
                  onClick={() => loadHistory(item)}
                  className="bg-white border border-gray-200 rounded-lg p-3 cursor-pointer hover:border-blue-400 hover:shadow-md transition-all group relative"
                >
                  <div className="flex justify-between items-start mb-2">
                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${item.mode === 'query' ? 'bg-blue-50 text-blue-600' : 'bg-purple-50 text-purple-600'}`}>
                      {item.mode.toUpperCase()}
                    </span>
                    <span className="text-[10px] text-gray-400 font-mono">{item.timestamp}</span>
                  </div>
                  <div className="text-xs font-bold text-gray-800 truncate group-hover:text-blue-600">{item.name}</div>
                  <div className="mt-2 flex flex-wrap gap-1">
                    <span className="text-[9px] bg-gray-50 text-gray-500 px-1 rounded border border-gray-100">{item.pov.scenario}</span>
                    <span className="text-[9px] bg-gray-50 text-gray-500 px-1 rounded border border-gray-100">{item.pov.year}</span>
                    {item.filters.entity && <span className="text-[9px] bg-blue-50 text-blue-500 px-1 rounded border border-blue-100">{item.filters.entity}</span>}
                  </div>
                  <button className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 p-1 text-gray-300 hover:text-red-500 transition-opacity">
                    <X className="w-3 h-3" />
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* 3. Filter Sidebar */}
        <div className="w-72 bg-white border-r border-gray-200 flex flex-col shrink-0">
          <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
            <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider flex items-center gap-2">
              <Filter className="w-3.5 h-3.5" /> 
              {searchMode === 'query' ? 'Query Filters' : 'Scan Scope'}
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-5 custom-scrollbar">
            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1.5 tracking-tighter">Entity Selection</label>
              <select 
                value={filters.entity}
                onChange={(e) => setFilters({...filters, entity: e.target.value})}
                className="w-full text-xs p-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-1 focus:ring-blue-500 focus:bg-white outline-none transition-all"
              >
                <option value="">-- All Base Entities --</option>
                <option value="China_HQ">China_HQ</option>
                <option value="US_Branch">US_Branch</option>
                <option value="EU_Sales">EU_Sales</option>
              </select>
            </div>

            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1.5 tracking-tighter">Account Member</label>
              <div className="relative">
                <Search className="absolute left-3 top-2.5 w-3.5 h-3.5 text-gray-400" />
                <input 
                  type="text"
                  placeholder="Filter account code..."
                  value={filters.account}
                  onChange={(e) => setFilters({...filters, account: e.target.value})}
                  className="w-full text-xs p-2.5 pl-9 bg-gray-50 border border-gray-200 rounded-lg focus:ring-1 focus:ring-blue-500 focus:bg-white outline-none"
                />
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-bold text-gray-400 uppercase mb-1.5 tracking-tighter">Period</label>
              <input 
                type="text"
                placeholder="Jan..Dec"
                value={filters.period}
                onChange={(e) => setFilters({...filters, period: e.target.value})}
                className="w-full text-xs p-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-1 focus:ring-blue-500"
              />
            </div>

            <div className="pt-4 border-t border-gray-100">
              <button 
                onClick={() => handleRun()}
                disabled={isProcessing}
                className={`w-full py-2.5 rounded-lg text-xs font-bold flex items-center justify-center gap-2 shadow-sm transition-all
                ${searchMode === 'query' 
                  ? 'bg-blue-600 text-white hover:bg-blue-700' 
                  : 'bg-purple-600 text-white hover:bg-purple-700'}`}
              >
                {isProcessing ? (
                   <Activity className="w-4 h-4 animate-pulse" />
                ) : (
                   searchMode === 'query' ? <Play className="w-3.5 h-3.5" /> : <Layers className="w-3.5 h-3.5" />
                )}
                {searchMode === 'query' ? 'Run Query' : 'Scan Data Block'}
              </button>
            </div>
          </div>
        </div>

        {/* 4. Result Workspace */}
        <div className="flex-1 flex flex-col min-w-0">
          {!hasData ? (
            <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
               <div className={`p-8 rounded-full mb-6 ${searchMode === 'query' ? 'bg-blue-50 text-blue-200' : 'bg-purple-50 text-purple-200'}`}>
                  {searchMode === 'query' ? <Search className="w-16 h-16" /> : <Radar className="w-16 h-16" />}
               </div>
               <h2 className="text-lg font-bold text-gray-800">Ready to Explore</h2>
               <p className="text-sm mt-2 max-w-xs text-center leading-relaxed font-medium">
                  {searchMode === 'query' 
                    ? "Adjust filters on the left and click 'Run Query' to fetch granular records." 
                    : "Use 'Scan Data Block' to visualize data distribution across dimensions."}
               </p>
            </div>
          ) : (
            <div className="flex-1 flex flex-col overflow-hidden animate-in fade-in slide-in-from-right-4 duration-500">
              {searchMode === 'query' ? (
