                            onClick={(e) => handleCellClick(e, row.entity, c.period)}
                            className={`w-12 h-8 rounded border border-white cursor-pointer hover:ring-2 hover:ring-blue-400 transition-all ${c.val === 0 ? 'bg-gray-50' : 'bg-purple-600'}`}
                          />
                        ))}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
