                        {row.data.map((c: any) => (
                          <div 
                            key={c.period} 
                            onClick={(e) => handleCellClick(e, row.entity, c.period)}
                            className={`w-12 h-8 rounded border border-white cursor-pointer hover:ring-2 hover:ring-blue-400 transition-all ${c.val === 0 ? 'bg-gray-50' : 'bg-purple-600'}`}
                          />
                        ))}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* 5. Cell Inspector Side Panel (Drawer) */}
          <div className={`absolute top-0 right-0 w-96 h-full bg-white shadow-2xl z-[100] border-l border-gray-200 transition-transform duration-300 transform ${selectedCell ? 'translate-x-0' : 'translate-x-full'}`}>
            {selectedCell && (
              <div className="h-full flex flex-col">
                <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
                  <h3 className="text-sm font-bold text-gray-800 uppercase tracking-wider flex items-center gap-2">
                    <ListFilter className="w-4 h-4 text-blue-600" /> Cell Inspector
                  </h3>
                  <button onClick={() => setSelectedCell(null)} className="p-1 hover:bg-gray-200 rounded transition-colors text-gray-400">
                    <X className="w-5 h-5" />
