                      className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${dim.location === 'pov' ? 'bg-white text-gray-400 border border-gray-200' : 'bg-blue-50 text-blue-600 border border-blue-100'}`}
                    >
                       Switch
                    </button>
                 </div>
               ))}
            </div>

            <div className="p-6 border-t border-gray-100 flex justify-end bg-gray-50/50">
               <button 
                 onClick={() => setShowPlacementModal(false)}
                 className="px-8 py-3 bg-blue-600 text-white rounded-2xl text-sm font-bold shadow-xl shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all"
               >
                 Apply Changes
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

