      if (dim) newDimValues[dim.id] = val;
    });
    setDimValues(newDimValues);
    setSearchMode(item.mode);
  };

  const togglePlacement = (id: string) => {
    setPlacements(prev => prev.map(p => 
      p.id === id ? { ...p, location: p.location === 'pov' ? 'param' : 'pov' } : p
    ));
