            ) : isProcessing ? (
              <div className="flex-1 flex flex-col items-center justify-center bg-white z-50">
                <Radar className={`w-8 h-8 mb-6 ${searchMode === 'discovery' ? 'text-purple-600 animate-pulse' : 'text-blue-600 animate-spin'}`} />
